#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long X; long long M; scanf("%lld %lld",&X,&M);
        long long k=0, pow=1;
        while(pow < X){ pow <<= 1; k++; }
        long long ans = (M > k) ? (M - k) : 0;
        printf("%lld\n", ans);
    }
    return 0;
}

